                    <div id="vt_card_307" data-id="307" data-image="../viewer/content/background_1752467829.webp" data-panorama="pano_1752466355517.jpg" data-code="8e98d81f8217304975ccb23337bb5761" data-lat="20.6836743869367" data-lon="105.74590205251995" class="card vt-card">
                <div class="card-img-block noselect">
                    <div id="panorama_preview_307" class="panorama_preview"></div>
                                            <img draggable="false" class="card-img-top" src="../viewer/content/background_1752467829.webp" alt="card image">
