                    <div id="vt_card_324" data-id="324" data-image="../viewer/content/background_1753070670.webp" data-panorama="pano_1753068921249.jpg" data-code="f2fc990265c712c49d51a18a32b39f0c" data-lat="21.023439465879978" data-lon="105.58476776459928" class="card vt-card">
