                    <div id="vt_card_327" data-id="327" data-image="../viewer/content/background_1753072303.webp" data-panorama="pano_1753067345109.jpg" data-code="b83aac23b9528732c23cc7352950e880" data-lat="21.01838823739327" data-lon="105.58622259879576" class="card vt-card">
