                    <div id="vt_card_331" data-id="331" data-image="../viewer/content/background_1753236869.webp" data-panorama="pano_1753235900828.jpg" data-code="6da37dd3139aa4d9aa55b8d237ec5d4a" data-lat="20.933862784850213" data-lon="105.79856731876083" class="card vt-card">
