<!-- <div id="chat-icon" onclick="toggleChat()"> -->
    <!-- <img src="/app/globe/img/chatbot.gif" alt="Chat Icon" width="200px"> -->
</div>

<!-- Popup chat box -->
<div id="chat-popup" class="hidden">
    <div class="chat-header">
        <span class="chat-popup-title-wrap">
            <span id="chat-popup-title">ĐOÀN THANH NIÊN CỘNG SẢN HỒ CHÍ MINH</span>
            <span id="chat-popup-subtitle">Powered by VR360</span>
        </span>
        <button onclick="toggleChat()">×</button>
    </div>
    <div id="chat-box">
        <div class="message bot"><p>Xin chào! Chúc bạn một ngày tốt lành, tôi có thể giúp được gì cho bạn? 😊</p></div>
    </div>
    <div class="input-container">
        <input type="text" id="user-input" placeholder="Nhập câu hỏi của bạn..." autocomplete="off">
        <button id="send-btn"><i class="fas fa-paper-plane"></i></button>
    </div>
</div>
<script src="/app/globe/js/marked.min.js"></script>
<script>
    // Biến quản lý trạng thái
    let isUserScrollingUp = false;
    /*
    let lastScrollPosition = 0;
    let currentChatStream = null;
    let isAnswering = false;
    let scrollTimeout = null;
    let lastUserScrollTime = 0;

    // Hiển thị/ẩn popup chat
    function toggleChat() {
        const chatPopup = document.getElementById('chat-popup');
        const chatContainerNew = document.getElementById('chat-icon');

        chatPopup.style.bottom = chatContainerNew.style.bottom;
        chatPopup.classList.toggle('hidden');

        // Reset trạng thái scroll khi mở chat
        if (!chatPopup.classList.contains('hidden')) {
            isUserInteracting = false;
            safeScroll(document.getElementById('chat-box'));
        }
    }

    // Gửi tin nhắn
    document.getElementById('send-btn').addEventListener('click', sendMessage);
    document.getElementById('user-input').addEventListener('keypress', function (e) {
        if (e.key === 'Enter') {
            if (isAnswering) {
                e.preventDefault();
                e.stopPropagation();
            }
            sendMessage();
        }
    });

    function sendMessage() {
        const userInput = document.getElementById('user-input');
        const message = userInput.value.trim();
        if (message === "") return;

        // Nếu đang trả lời câu hỏi cũ, hủy nó trước
        if (isAnswering && currentChatStream) {
            currentChatStream.close();
            currentChatStream = null;

            // Thêm thông báo hủy câu trả lời trước
            const chatBox = document.getElementById('chat-box');
            const cancelNotice = document.createElement('div');
            cancelNotice.classList.add('message', 'system');
            cancelNotice.innerHTML = '<p>Đã hủy câu trả lời trước để xử lý câu hỏi mới</p>';
            chatBox.appendChild(cancelNotice);
            safeScroll(chatBox);
        }

        // Reset trạng thái
        isUserScrollingUp = false;
        isAnswering = true;
        toggleLoadingState(true);

        // Hiển thị tin nhắn của người dùng
        displayMessage(message, 'user');
        userInput.value = '';

        // Hiển thị tin nhắn bot với loading dots
        const chatBox = document.getElementById('chat-box');
        const botMessage = document.createElement('div');
        botMessage.classList.add('message', 'bot');
        botMessage.innerHTML = `<p><span id="loading-dots"><span>.</span><span>.</span><span>.</span></span></p>`;
        chatBox.appendChild(botMessage);
        safeScroll(chatBox);

        chatBox.addEventListener('scroll', handleScroll);

        // Sử dụng EventSource để nhận stream
        currentChatStream = new EventSource(`ajax/chatbot.php?message=${encodeURIComponent(message)}`);

        let currentBotMessage = botMessage;
        let fullContent = '';

        currentChatStream.onmessage = function(event) {
            let data;
            try {
                data = JSON.parse(event.data);
            } catch (e) {
                console.error('Invalid JSON:', event.data);
                return;
            }

            if (data.error) {
                currentBotMessage.innerHTML = `<p>${data.error}</p>`;
                currentChatStream.close();
                return;
            }

            if (data.status === 'start') {
                // Giữ nguyên hiệu ứng loading, không hiển thị gì thêm
                fullContent = '';
            } else if (data.content) {
                // Nếu đây là nội dung đầu tiên sau khi start
                if (fullContent === '') {
                    // Ẩn loading dots và tạo message mới
                    botMessage.style.display = 'none';
                    currentBotMessage = document.createElement('div');
                    currentBotMessage.classList.add('message', 'bot');
                    currentBotMessage.innerHTML = `<p>${data.content.replace(/\n/g, '<br>')}</p>`;
                    chatBox.appendChild(currentBotMessage);
                } else {
                    // Thêm nội dung stream vào div hiện tại
                    const p = currentBotMessage.querySelector('p');
                    p.innerHTML += data.content.replace(/\n/g, '<br>');
                }

                if (!isUserScrollingUp) {
                    safeScroll(chatBox);
                }
                fullContent += data.content;
            } else if (data.status === 'end') {
                // Kết thúc địa điểm
                const p = currentBotMessage.querySelector('p');
                p.innerHTML = marked.parse(fullContent);

                if (!isUserScrollingUp) {
                    safeScroll(chatBox);
                }

                const links = document.querySelectorAll('.message.bot a');
                links.forEach(link => {
                    link.setAttribute('target', '_blank');
                    link.textContent = 'Liên kết';
                });
            } else if (event.data === '[DONE]') {
                // Kết thúc stream
                const p = currentBotMessage.querySelector('p');
                p.innerHTML = marked.parse(fullContent);
                if (!isUserScrollingUp) {
                    safeScroll(chatBox);
                }

                const links = document.querySelectorAll('.message.bot a');
                links.forEach(link => {
                    link.setAttribute('target', '_blank');
                });

                currentChatStream.close();
                chatBox.removeEventListener('scroll', handleScroll);
                isAnswering = false;
                toggleLoadingState(false);
            }
        };

        currentChatStream.onerror = function() {
            if (currentBotMessage.innerHTML.includes('loading-dots')) {
                currentBotMessage.innerHTML = `<p>Xin lỗi, có lỗi xảy ra. Vui lòng thử lại.</p>`;
            }
            currentChatStream.close();
            chatBox.removeEventListener('scroll', handleScroll);
            isAnswering = false;
            toggleLoadingState(false);
        };
    }

    function handleScroll() {
        const chatBox = document.getElementById('chat-box');
        const currentPosition = chatBox.scrollTop;
        const isNearBottom = currentPosition + chatBox.clientHeight >= chatBox.scrollHeight - 50;

        clearTimeout(scrollTimeout);

        if (!isNearBottom) {
            isUserScrollingUp = true;
            lastUserScrollTime = Date.now();
        }

        scrollTimeout = setTimeout(() => {
            if (Date.now() - lastUserScrollTime > 5000) {
                isUserScrollingUp = false;
                safeScroll(chatBox);
            }
        }, 5000);

        lastScrollPosition = currentPosition;
    }

    function safeScroll(chatBox) {
        if (!isUserScrollingUp) {
            setTimeout(() => {
                chatBox.scrollTo({
                    top: chatBox.scrollHeight,
                    behavior: 'smooth'
                });
                const indicator = document.getElementById('new-message-indicator');
                if (indicator) indicator.remove();
            }, 50);
        } else {
            displayNewMessageIndicator();
        }
    }

    function displayMessage(message, sender) {
        const chatBox = document.getElementById('chat-box');
        const messageElement = document.createElement('div');
        messageElement.classList.add('message', sender);
        messageElement.innerHTML = `<p>${message.replace(/\n/g, '<br>')}</p>`;
        chatBox.appendChild(messageElement);
        safeScroll(chatBox);
    }

    function displayNewMessageIndicator() {
        if (isUserScrollingUp && !document.getElementById('new-message-indicator')) {
            const indicator = document.createElement('div');
            indicator.id = 'new-message-indicator';
            indicator.innerHTML = 'Có tin nhắn mới ↓';
            indicator.onclick = () => {
                isUserScrollingUp = false;
                safeScroll(document.getElementById('chat-box'));
                indicator.remove();
            };
            document.getElementById('chat-popup').appendChild(indicator);
        }
    }

    function toggleLoadingState(isLoading) {
        const sendBtn = document.getElementById('send-btn');
        const userInput = document.getElementById('user-input');

        if (isLoading) {
            sendBtn.classList.add('loading');
            sendBtn.disabled = true;
            userInput.disabled = true;
        } else {
            sendBtn.classList.remove('loading');
            sendBtn.disabled = false;
            userInput.disabled = false;
            userInput.focus();
        }
    }

    // Xử lý khi resize window
    window.addEventListener('resize', () => {
        if (!isUserScrollingUp) {
            safeScroll(document.getElementById('chat-box'));
        }
    });
    */

</script>
