            window.boundaries = [];
            window.bottom_chat = '50px';
            window.link_space = "https://3dspace.vr360.com.vn/Md6Mrsu/thanh-doan-ha-noi";

            window.return_globe = function() {
                $('#vt_viewer').fadeOut(200);
                $('#btn_return_globe').hide();
                setTimeout(function() {
                    $('#vt_viewer iframe').attr('src', '');
                    $('#vt_viewer iframe').css('opacity', 0);
                    $('#vt_viewer').css('z-index', 0);
                    $('#btn_return_globe').css('z-index', 0);
                }, 200);

                $('#vnlp-chat-container').attr('style', 'bottom: ' + window.bottom_chat + ' !important; display: block !important');
            }

            $(document).ready(function() {
                if (mobileCheck()){
                    $('.paginate_mb').append(`<div class="list-vt-pagination"></div>`);
                }else{
                    $('.paginate_mb .list-vt-pagination').remove();
                }
                window.init_globe_map();
                window.initContentBoxDateTime();
                window.parse_map_points_g(window.points)

                $('#selectDisstrict').on("click", function() {
                    $("#districtSelection").toggle();
                });

                $('#districtSelection .option').on("click", function() {
                    var that = this;
                    var data = window.points;
                    var selectedId = $(that).data("id");
                    var selectedTitle = $(that).data("title");
                    var center = $(that).data("center");

                    if (selectedId != '-1'){
                        data = window.points.filter(item => item.image !== null && item.image != '' && item.district_id === `${selectedId}`)
                        $('#title_district').html(selectedTitle)
                    }else{
                        $('#title_district').html("THÀNH ĐOÀN HÀ NỘI")
                    }
                    show_intro_map();
                    window.renderListVr360(data);

                    $("#selectDisstrict .select .name").data("district_id", selectedId);
                    $("#selectDisstrict .select .name").html(selectedTitle);
                    $("#districtSelection").hide();
                    window.showBoundaries(selectedId);
                    window.map_globe_l.flyTo(center, 13)
                });

                $('#list_district_mb .option').on("click", function() {
                    var that = this;
                    var selectedId = $(that).data("id");
                    var selectedTitle = $(that).data("title");
                    var center = $(that).data("center");
                    $("#selectDisstrict .select .name").data("district_id", selectedId);
                    $("#selectDisstrict .select .name").html(selectedTitle);
                    $("#list_district_mb").hide();
                    window.showBoundaries(selectedId);
                    window.map_globe_l.flyTo(center, 13)
                });

                // init list of vt
                $('.list-vt-pagination').pagination({
                    dataSource: window.points.filter(item => item.image !== null && item.image != ''),
                    pageSize: 9,
                    position: 'top',
                    showNavigator: true,
                    formatNavigator: "| <%= totalNumber %> địa điểm",
                    callback: function(data, pagination) {
                        var html = window.createItemListHtml(data);
                        $('#list-vt').html(html);
                    }
                })

                $("a.all-project-button").on('click', function() {
                    $('#imageDialog').show();
                });
                $('#filterDistrict').on("click", function() {
                    $("#districList").toggle();
                });
                $('#close-city-country-picker').on("click", function() {
                    $("#districList").toggle();
                });


                $('#districList .option').on("click", function() {
                    var that = this;
                    var selectedId = $(that).data("id");
                    var selectedTitle = $(that).data("title");
                    var center = $(that).data("center");
                    window.showBoundaries(selectedId);
                    window.map_globe_l.setView(center, 13);
                });

                $("#txtSearchMap").on('input', function() {
                    var cssSearchMap = '.polygon2-box:after {border-radius: 6px 6px 0 0}';
                    addCss(cssSearchMap);
                    var searchValue = $(this).val();
                    handleSearchPOI(searchValue);
                });

                $("#txtSearchMap").on('focus', function() {
                    if ($(this).val().trim() != '') {
                        $('#searchResult').toggle();
                        var cssSearchMap = '.polygon2-box:after {border-radius: 6px 6px 0 0}';
                        addCss(cssSearchMap);
                    }
                });
                $("#txtSearchMap").on('blur', function() {
                    setTimeout(function() {
                        $('#searchResult').hide();
                        var cssSearchMap = '.polygon2-box:after {border-radius: 6px}';
                        addCss(cssSearchMap);
                    }, 2000)

                });

                function addCss(css) {
                    $('<style>').prop('type', 'text/css').html(css).appendTo('head');
                }

                function handleSearchPOI(searchValue, isToggle = true) {
                    if (searchValue == '') {
                        $('#searchResult').hide();
                        $('#searchResult ul').html('');
                        var cssSearchMap = '.polygon2-box:after {border-radius: 6px}';
                        addCss(cssSearchMap);
                        return;
                    }
                    var result = searchLocation(searchValue);
                    if (result && result.length > 0) {
                        $('#searchResult ul').html('');
                        for (var i = 0; i < 10; i++) {
