                window.toggleMapLayer = function toggleMapLayer(mapLayerId, baseMapLayerName) {
                    var mapLayers = document.getElementsByClassName('map-layer-item');

                    if ($('#map-layer-items').hasClass('open_map_layer')){
                        for (var i = 0; i < mapLayers.length; i++) {
                            mapLayers[i].classList.add('hidden');
                            mapLayers[i].classList.remove('active_map_layer');
                        }

                        if (mapLayerId) {
                            $("#" + mapLayerId).removeClass('hidden');
                            $("#" + mapLayerId).addClass('active_map_layer');
                        }

                        $('#map-layer-items').removeClass('open_map_layer');

                        if (baseMapLayerName == 'street_basemap') {
                            window.map_globe_l.removeLayer(window.satellite_basemap);
                            window.map_globe_l.removeLayer(window.openstreetmap_basemap);
                            // window.map_globe_l.removeLayer(window.map4d_basemap);
                            window.street_basemap.addTo(window.map_globe_l);
                        } else if (baseMapLayerName == 'satellite_basemap') {
                            window.map_globe_l.removeLayer(window.street_basemap);
                            window.map_globe_l.removeLayer(window.openstreetmap_basemap);
                            // window.map_globe_l.removeLayer(window.map4d_basemap);
