                function createTabContent(tab_content, type) {
                    $.ajax({
                        url: "ajax/get_news.php",
                        type: "GET",
                        data: {
                            type: type
                        },
                        async: true,
                        success: function(json) {
                            var rsp = JSON.parse(json);
                            if (rsp.news) {
                                var html = "";
                                $.each(rsp.news, function(index, item) {
                                    html += `<div class="news-item">
                                            <div class="thumb-art" data-link="${item.url}">
                                                <img src="${item.image_url}" alt="${item.name}">
                                            </div>
                                            <div class="news-text">
                                                <a target="_blank" href="${item.url}">${item.name}</a>
                                                <p>${item.summary}</p>
                                            </div>
                                        </div>`
                                });
                                $("#" + tab_content + "").html(html);
                            }
                        }
                    });
                }

                function searchLocation(searchValue) {
                    var value = convertViToEn(searchValue);
                    return window.points.filter(item => convertViToEn(item.title).includes(value));
                }

                function convertViToEn(str, toUpperCase = false) {
                    str = str.toLowerCase();
                    str = str.replace(/à|á|ạ|ả|ã|â|ầ|ấ|ậ|ẩ|ẫ|ă|ằ|ắ|ặ|ẳ|ẵ/g, "a");
                    str = str.replace(/è|é|ẹ|ẻ|ẽ|ê|ề|ế|ệ|ể|ễ/g, "e");
                    str = str.replace(/ì|í|ị|ỉ|ĩ/g, "i");
                    str = str.replace(/ò|ó|ọ|ỏ|õ|ô|ồ|ố|ộ|ổ|ỗ|ơ|ờ|ớ|ợ|ở|ỡ/g, "o");
                    str = str.replace(/ù|ú|ụ|ủ|ũ|ư|ừ|ứ|ự|ử|ữ/g, "u");
                    str = str.replace(/ỳ|ý|ỵ|ỷ|ỹ/g, "y");
                    str = str.replace(/đ/g, "d");
                    // Some system encode vietnamese combining accent as individual utf-8 characters
                    str = str.replace(/\u0300|\u0301|\u0303|\u0309|\u0323/g, ""); // Huyền sắc hỏi ngã nặng
                    str = str.replace(/\u02C6|\u0306|\u031B/g, ""); // Â, Ê, Ă, Ơ, Ư

                    return toUpperCase ? str.toUpperCase() : str;
                }
            });
