    <script>
        $(document).ready(function() {
            function scrollbottom() {
                var elementToScroll = document.getElementById("chat_converse");
                elementToScroll.scrollTop = elementToScroll.scrollHeight;
            }

            function pushMessUser(message) {
                var chatConverse = document.getElementById("chat_converse");
                var newElement = document.createElement("span");
                newElement.className = "chat_msg_item chat_msg_item_user";
                newElement.textContent = message;
                chatConverse.appendChild(newElement);
            }

            function pushMessAdmin(message) {
                var chatConverse = document.getElementById("chat_converse");
                var newSpan = document.createElement("span");
                newSpan.className = "chat_msg_item chat_msg_item_admin";
                var divAvatar = document.createElement("div");
                divAvatar.className = "chat_avatar";
                var img = document.createElement("img");
                img.src = "img/chatbot-ai.png";
                var spanContent = document.createTextNode(message);
                divAvatar.appendChild(img);
                newSpan.appendChild(divAvatar);
                newSpan.appendChild(spanContent);
                chatConverse.appendChild(newSpan);
            }

            let sessionData
            async function getSession() {
                const session = await fetch(`../../assets/chatbot/api/chats/initial_session/?bot_id=${9}`, {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                    },
                });
                sessionData = await session.json();
            }
            getSession();



            $("#fab_send").on("click", (e) => {
                let textarea = document.getElementById("chatSend");
                let mess = textarea.value;
                if (mess) {
                    calMess(mess);
                    textarea.value = '';
                }
            })

            async function calMess(mess) {
                if (mess) {
                    console.log("User pressed Enter with message: " + mess);
                    pushMessUser(mess);
                    scrollbottom();

                    let url = `../../assets/chatbot/api/chats/chat/?token=${sessionData.token}&message=${mess}&stream=1`;
                    const response = await fetch(url, {
                        method: "POST",
                        headers: {
                            "Content-Type": "application/json",
                        },
                    });

                    const reader = response.body.getReader();
                    let partialMessage = '';
                    let currentWord = '';
                    let i = 0;
                    var message = '';

                    var chatConverse = document.getElementById("chat_converse");
                    var newSpan = document.createElement("span");
                    newSpan.className = "chat_msg_item chat_msg_item_admin";
                    var divAvatar = document.createElement("div");
                    divAvatar.className = "chat_avatar";
                    var img = document.createElement("img");
                    img.src = "img/chatbot-ai.png";
                    var spanContent = document.createTextNode('');
                    divAvatar.appendChild(img);
                    newSpan.appendChild(divAvatar);
                    newSpan.appendChild(spanContent);
                    chatConverse.appendChild(newSpan);

                    const readChunk = async () => {
                        const {
                            done,
                            value
                        } = await reader.read();
                        if (done) {
                            i = 0;
                            return;
                        }

                        const chunk = new TextDecoder().decode(value);
                        const words = chunk.split('');

                        for (const word of words) {
                            const characters = word.split('');
                            characters.forEach(async (character, index) => {
                                await new Promise(resolve => setTimeout(resolve, 10 * i + index));
                                message += character;
                                var spanContent = document.createTextNode(character);
                                newSpan.appendChild(spanContent);
                                scrollbottom();
                            });
                            i += characters.length;
                        }

                        currentWord = words[words.length - 1];
                        partialMessage = partialMessage + ' ' + chunk;
                        i++;
                        await readChunk();
                    };
                    await readChunk();
                    scrollbottom();
                }
            }


            $("#chatSend").on("keydown", async function(event) {
                if (event.which === 13 && !event.shiftKey) {
                    event.preventDefault();
                    var message = $.trim($(this).val());
                    $(this).val("");
                    calMess(message);
                }
            });

            $("#fab_camera").on("click", (e) => {
                let mic_icon = document.querySelector(".fab_field .fab>i");
                if (mic_icon.style.color === "rgb(66, 165, 245)") {
                    mic_icon.style.color = "#bbb"
                    console.log('off');
                } else {
                    mic_icon.style.color = '#42a5f5'
                    console.log('on');
                }
            });

            document.addEventListener("keydown", function(e) {
                if (e.key === "Escape") {
                    document.getElementById('imageDialog').style.display = 'none';
                    $('#guide_modal').hide();
                    $("#contentBox").hide();
                    $('#game_modal').hide();
                }
                if (e.key === "Home") {
                    window.map_globe_l.flyTo([20.577531, 105.9120985], 13, true);
                }
                if (e.ctrlKey && (e.keyCode == "61" || e.keyCode == "107" || e.keyCode == "173" || e.keyCode == "109" || e.keyCode == "187" || e.keyCode == "189")) {
                    e.preventDefault();
                }
            });

            document.addEventListener("wheel",function (e) {
                if (e.ctrlKey) {e.preventDefault();}},{passive: false}
            );

            //window.renderListVr360(window.points);
        });
    </script>
